import type { CesarPlan, CesarPlanStep } from './plan.js';

// @kern-source: plan-formatter:3
export function formatStepType(s: CesarPlanStep): string {
  switch (s.type) {
    case 'self': return 'self: Cesar';
    case 'forge': return `forge: ${(s.engines ?? []).join(', ')}`;
    case 'teamforge': return `teamforge: ${(s.engines ?? []).join(', ')}`;
    case 'delegate': return `delegate: ${s.engine ?? 'unknown'}`;
    case 'brainstorm': return `brainstorm: ${(s.engines ?? []).join(', ')}`;
    case 'campfire': return `campfire: ${(s.engines ?? []).join(', ')}`;
    case 'tribunal': return `tribunal: ${(s.engines ?? []).join(', ')}${s.tribunalMode ? ' — ' + s.tribunalMode : ''}`;
    case 'pipeline': return `pipeline: ${(s.engines ?? []).join(', ')}`;
    default: return s.type;
  }
}

// @kern-source: plan-formatter:18
export function formatCesarPlanMarkdown(plan: CesarPlan): string {
  const lines: string[] = [];
  lines.push(`# Plan: ${plan.intent}`);
  lines.push('');
  lines.push(`- Plan ID: \`${plan.id}\``);
  if (plan.planFilePath) lines.push(`- Plan file: \`${plan.planFilePath}\``);
  lines.push(`- Created: ${plan.createdAt}`);
  lines.push(`- Status: ${plan.state}`);
  lines.push('');
  if (plan.planningCost && typeof plan.planningCost.tokens === 'number') {
    const costStr = typeof plan.planningCost.costUsd === 'number' ? ` ($${plan.planningCost.costUsd.toFixed(4)})` : '';
    lines.push(`> Planning cost: ~${plan.planningCost.tokens.toLocaleString()} tokens${costStr}`);
    lines.push('');
  }
  // OpenCode add#2: surface every fitnessCmd verbatim BEFORE the per-step
  // detail so the user reading the markdown sees every shell command they
  // are about to run before they type Y. fitnessCmd is LLM-controlled and
  // executes via `/bin/sh -c` — this is the user's last opportunity to
  // catch a malicious or wrong command.
  const stepsWithFitness = plan.steps.filter((s: CesarPlanStep) => s.fitnessCmd && s.fitnessCmd.trim().length > 0);
  if (stepsWithFitness.length > 0) {
    lines.push('## Shell Commands');
    lines.push('');
    lines.push('The following shell commands will be executed by this plan. Read them carefully before approving:');
    lines.push('');
    for (const s of stepsWithFitness) {
      lines.push(`- **${s.id}** (${s.type}): \`${s.fitnessCmd}\``);
    }
    lines.push('');
  }

  lines.push('## Steps');
  lines.push('');

  for (let i = 0; i < plan.steps.length; i++) {
    const s = plan.steps[i];
    const num = i + 1;
    const typeLabel = formatStepType(s);
    const state = s.state ?? 'pending';
    lines.push(`### Step ${num}: ${s.description}`);
    lines.push(`- Type: ${typeLabel}`);
    lines.push(`- State: ${state}`);

    if (s.rationale) lines.push(`- Rationale: ${s.rationale}`);
    if (s.fitnessCmd) lines.push(`- Fitness: \`${s.fitnessCmd}\``);
    if (s.verifyCmd) lines.push(`- Verify: \`${s.verifyCmd}\``);
    if (s.dependsOn && s.dependsOn.length > 0) lines.push(`- Depends on: ${s.dependsOn.join(', ')}`);
    if (s.exports && s.exports.length > 0) lines.push(`- Exports: ${s.exports.join(', ')}`);
    if (s.imports && s.imports.length > 0) lines.push(`- Imports: ${s.imports.join(', ')}`);

    if (s.result) {
      lines.push(`- Actual: ${s.result.actualTokens.toLocaleString()} tokens ($${s.result.actualCostUsd.toFixed(4)}) — ${(s.result.durationMs / 1000).toFixed(1)}s`);
    } else {
      lines.push(`- Est: ~${s.estimatedTokens.toLocaleString()} tokens ($${s.estimatedCostUsd.toFixed(2)})`);
    }
    lines.push('');
  }

  lines.push('---');
  if (plan.totalActualTokens > 0) {
    lines.push(`**Planned: ~${plan.totalEstimatedTokens.toLocaleString()} tokens ($${plan.totalEstimatedCostUsd.toFixed(2)})**`);
    lines.push(`**Actual: ${plan.totalActualTokens.toLocaleString()} tokens ($${plan.totalActualCostUsd.toFixed(2)})**`);
  } else {
    lines.push(`**Total estimated: ~${plan.totalEstimatedTokens.toLocaleString()} tokens ($${plan.totalEstimatedCostUsd.toFixed(2)})**`);
  }
  const allEngines = [...new Set(plan.steps.flatMap((s: CesarPlanStep) => s.engines ?? (s.engine ? [s.engine] : [])))];
  if (allEngines.length > 0) {
    lines.push(`**Engines: ${allEngines.join(', ')}**`);
  }
  lines.push(`**Status: ${plan.state}**`);
  if (plan.planFilePath) lines.push(`**Plan file: ${plan.planFilePath}**`);

  return lines.join('\n');
}
